/**
 * useModel hook
 * =============
 * Provides CRUD operations and data fetching for a specific model.
 *
 * Example:
 *   const { data, isLoading } = useModelList("sales_order", { page: 1 });
 *   const { data: record } = useModel("sales_order", recordId);
 *   const { createRecord, updateRecord } = useModel("sales_order");
 */

import { useCallback } from "react";
import { useQuery, useMutation, useQueryClient, type UseQueryResult } from "@tanstack/react-query";
import { queryKeys } from "~/lib/query-keys";

export interface FilterCondition {
  field: string;
  op: "eq" | "neq" | "gt" | "gte" | "lt" | "lte" | "like" | "ilike" | "in" | "between" | "is_null" | "is_not_null";
  value?: unknown;
}

export interface FilterGroup {
  logic: "and" | "or";
  conditions: FilterCondition[];
}

interface ListOptions {
  page?: number;
  limit?: number;
  orderBy?: string;
  orderDir?: "asc" | "desc";
  filters?: FilterGroup;
}

interface ListResponse {
  data: Record<string, unknown>[];
  meta: {
    page: number;
    limit: number;
    total: number;
    filters?: FilterGroup;
    sort?: Array<{ field: string; order: "asc" | "desc" }>;
  };
}

/**
 * Fetch a paginated list of records.
 */
export function useModelList(
  model: string,
  options?: ListOptions
): UseQueryResult<ListResponse> {
  const params = new URLSearchParams({
    page: String(options?.page ?? 1),
    limit: String(options?.limit ?? 50),
    ...(options?.orderBy ? { orderBy: options.orderBy, orderDir: options.orderDir ?? "asc" } : {}),
  });

  // Add filters if provided
  if (options?.filters && options.filters.conditions.length > 0) {
    params.set("filters", JSON.stringify(options.filters));
  }

  return useQuery({
    queryKey: queryKeys.models.list(model, options),
    queryFn: async (): Promise<ListResponse> => {
      const res = await fetch(`/api/${model}?${params}`);
      if (!res.ok) throw new Error(`Failed to fetch ${model} list`);
      return (await res.json()) as ListResponse;
    },
  });
}

/**
 * Fetch a single record by ID.
 */
export function useModel(
  model: string,
  recordId?: string
): UseQueryResult<Record<string, unknown>> & {
  createRecord?: (newData: Record<string, unknown>) => Promise<Record<string, unknown>>;
  updateRecord?: (recordId: string, newData: Record<string, unknown>) => Promise<Record<string, unknown>>;
  isMutating?: boolean;
} {
  const queryClient = useQueryClient();

  const query = useQuery({
    queryKey: queryKeys.models.detail(model, recordId),
    queryFn: async (): Promise<Record<string, unknown>> => {
      if (!recordId) return {};
      const res = await fetch(`/api/${model}/${recordId}`);
      if (!res.ok) throw new Error(`Failed to fetch ${model}/${recordId}`);
      return (await res.json()).data as Record<string, unknown>;
    },
    enabled: !!recordId,
  });

  const createMutation = useMutation<
    Record<string, unknown>,
    Error,
    Record<string, unknown>
  >({
    mutationFn: async (data: Record<string, unknown>) => {
      const res = await fetch(`/api/${model}`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (!res.ok) throw new Error("Create failed");
      return (await res.json()).data as Record<string, unknown>;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.models.lists(model) });
    },
  });

  const updateMutation = useMutation<
    Record<string, unknown>,
    Error,
    { id: string; data: Record<string, unknown> }
  >({
    mutationFn: async ({ id, data }: { id: string; data: Record<string, unknown> }) => {
      const res = await fetch(`/api/${model}/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(data),
      });
      if (!res.ok) throw new Error("Update failed");
      return (await res.json()).data as Record<string, unknown>;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.models.details(model) });
    },
  });

  // Stable function references to avoid downstream re-renders
  const createRecord = useCallback(
    (data: Record<string, unknown>) => createMutation.mutateAsync(data),
    [createMutation]
  );

  const updateRecord = useCallback(
    (id: string, data: Record<string, unknown>) => updateMutation.mutateAsync({ id, data }),
    [updateMutation]
  );

  return {
    ...query,
    createRecord,
    updateRecord,
    isMutating: createMutation.isPending || updateMutation.isPending,
  };
}
